script.code:
const rows = {{node:search_existing_gr_link.data.data}};
const arr = Array.isArray(rows) ? rows : (rows ? [rows] : []);
return { alreadyLinked: arr.length > 0 ? 1 : 0 };

const gdTable = {{workflowparams:gd_table}} || [];
const soSet = {};
const batchSet = {};
for (const l of gdTable) {
  if (!l) continue;
  if (l.line_so_id) soSet[String(l.line_so_id)] = true;
  let tqd = [];
  try { tqd = l.temp_qty_data ? JSON.parse(l.temp_qty_data) : []; } catch (e) { tqd = []; }
  if (!Array.isArray(tqd)) tqd = [];
  for (const t of tqd) { if (t && t.batch_id) batchSet[String(t.batch_id)] = true; }
}
let soIds = Object.keys(soSet);
if (soIds.length === 0) soIds = ["0"];
let batchIds = Object.keys(batchSet);
if (batchIds.length === 0) batchIds = ["0"];
return { soIds: soIds, batchIds: batchIds };

const poRows = {{node:search_po.data.data}};
const pos = Array.isArray(poRows) ? poRows : (poRows ? [poRows] : []);
const buyerOrg = {{workflowparams:buyer_org}} || '';
const itsRows = {{node:search_its.data.data}};
const itsArr = Array.isArray(itsRows) ? itsRows : (itsRows ? [itsRows] : []);

const baseLines = [];
const itemIdSet = {};
const poIdList = [];
const poNoList = [];
let supplierId = '';
let currencyCode = '';
let first = null;

for (const po of pos) {
  if (!po) continue;
  if (!first) first = po;
  if (po.id) poIdList.push(po.id);
  if (po.purchase_order_no) poNoList.push(po.purchase_order_no);
  if (!supplierId && po.po_supplier_id) supplierId = po.po_supplier_id;
  if (!currencyCode && po.po_currency) currencyCode = po.po_currency;
  const lines = po.table_po || [];
  for (const item of lines) {
    if ((item.received_qty || 0) >= (item.quantity || 0)) continue;
    const recv = parseFloat(((item.quantity || 0) - (item.received_qty || 0) - (item.created_received_qty || 0)).toFixed(3));
    if (recv <= 0) continue;
    if (item.item_id) itemIdSet[String(item.item_id)] = true;
    baseLines.push({
      item_id: item.item_id || null,
      item_name: item.item_name,
      item_desc: item.item_desc,
      more_desc: item.more_desc,
      ordered_qty: item.quantity,
      ordered_qty_uom: item.quantity_uom || null,
      to_received_qty_uom: item.quantity_uom || null,
      received_qty: recv,
      item_uom: item.quantity_uom || null,
      line_po_no: po.purchase_order_no,
      initial_received_qty: parseFloat((item.received_qty || 0).toFixed(3)),
      line_po_id: po.id,
      unit_price: item.unit_price,
      total_price: item.po_amount,
      line_remark_1: item.line_remark_1,
      line_remark_2: item.line_remark_2,
      po_line_item_id: item.id,
      item_category_id: item.item_category_id || null
    });
  }
}

let itemIds = Object.keys(itemIdSet);
if (itemIds.length === 0) itemIds = ["0"];
const supplierIds = supplierId ? [String(supplierId)] : ["0"];

// Setups are unique per (buyer_org, buyer_supplier); the buyer+seller query can
// return several. Pick the row for THIS PO's supplier, else the enabled one.
let itsMatch = itsArr.find(function (r) { return r && String(r.buyer_supplier_id) === String(supplierId); });
if (!itsMatch) itsMatch = itsArr.find(function (r) { return r && Number(r.auto_create_gr) === 1; }) || itsArr[0] || null;
const buyerPlant = (itsMatch && itsMatch.buyer_plant_id) ? itsMatch.buyer_plant_id : '';
const skipPutaway = (itsMatch && Number(itsMatch.skip_putaway) === 1) ? 1 : 0;

return {
  baseLines: baseLines,
  skipPutaway: skipPutaway,
  itemIds: itemIds,
  supplierId: supplierId || '',
  supplierIds: supplierIds,
  currencyCode: currencyCode || '',
  poNos: poNoList.join(', '),
  poIds: poIdList,
  organizationId: buyerOrg,
  plantId: buyerPlant || (first && first.po_plant ? first.po_plant : ''),
  grRemark1: first && first.po_remark ? first.po_remark : '',
  grRemark2: first && first.po_remark2 ? first.po_remark2 : '',
  grRemark3: first && first.po_remark3 ? first.po_remark3 : '',
  grRemark4: first && first.po_remark4 ? first.po_remark4 : '',
  grRemark5: first && first.po_remark5 ? first.po_remark5 : '',
  lineCount: baseLines.length
};

const rows = {{node:search_storage_location.data.data}};
const arr = Array.isArray(rows) ? rows : (rows ? [rows] : []);
const slId = arr.length > 0 && arr[0] ? arr[0].id : '';
return { slId: slId || '', slIds: slId ? [String(slId)] : ["0"] };

const rows = {{node:search_supplier.data.data}};
const s = Array.isArray(rows) ? rows[0] : rows;
const countryIds = [];
const stateIds = [];
let currencyId = '';
if (s) {
  currencyId = s.currency_id || '';
  const addrs = (s.address_list || []).filter(a => a.switch_save_as_default);
  for (const a of addrs) {
    if (a.address_country_id) countryIds.push(String(a.address_country_id));
    if (a.adddress_state) stateIds.push(String(a.adddress_state));
  }
}
let cIds = Array.from(new Set(countryIds)); if (cIds.length === 0) cIds = ["0"];
let sIds = Array.from(new Set(stateIds)); if (sIds.length === 0) sIds = ["0"];
return {
  countryIds: cIds,
  stateIds: sIds,
  currencyIds: currencyId ? [String(currencyId)] : ["0"]
};

const baseLines = {{node:code_build_lines.data.baseLines}} || [];
const items = {{node:search_items.data.data}};
const itemArr = Array.isArray(items) ? items : (items ? [items] : []);
const putawayRows = {{node:search_putaway_setup.data.data}};
const putawayArr = Array.isArray(putawayRows) ? putawayRows : (putawayRows ? [putawayRows] : []);
const putawaySetup = putawayArr.length > 0 ? putawayArr[0] : null;
const binRows = {{node:search_bin_location.data.data}};
const binArr = Array.isArray(binRows) ? binRows : (binRows ? [binRows] : []);
const defaultBinLocation = binArr.length > 0 ? binArr[0].id : '';
const defaultStorageLocation = {{node:code_sl.data.slId}} || '';
const accRows = {{node:search_acc.data.data}};
const accArr = Array.isArray(accRows) ? accRows : (accRows ? [accRows] : []);
const accType = accArr.length > 0 ? accArr[0].acc_integration_type : '';
const ruleRows = {{node:search_gr_rule.data.data}};
const ruleArr = Array.isArray(ruleRows) ? ruleRows : (ruleRows ? [ruleRows] : []);
const grNoType = ruleArr.length > 0 ? ruleArr[0].id : '';

const supplierRows = {{node:search_supplier.data.data}};
const supplier = Array.isArray(supplierRows) ? supplierRows[0] : supplierRows;
const currencyRows = {{node:search_supplier_currency.data.data}};
const currencyArr = Array.isArray(currencyRows) ? currencyRows : (currencyRows ? [currencyRows] : []);
const supplierCurrencyCode = currencyArr.length > 0 ? currencyArr[0].currency_code : '';
const purposeRows = {{node:search_addr_purpose.data.data}};
const purposeArr = Array.isArray(purposeRows) ? purposeRows : (purposeRows ? [purposeRows] : []);
const shippingPurposeId = purposeArr.length > 0 ? purposeArr[0].id : '';
const countryRows = {{node:search_addr_country.data.data}};
const countryArr = Array.isArray(countryRows) ? countryRows : (countryRows ? [countryRows] : []);
const stateRows = {{node:search_addr_state.data.data}};
const stateArr = Array.isArray(stateRows) ? stateRows : (stateRows ? [stateRows] : []);

const supplierId = {{node:code_build_lines.data.supplierId}} || '';
const poCurrency = {{node:code_build_lines.data.currencyCode}} || '';
const poNos = {{node:code_build_lines.data.poNos}} || '';
const poIds = {{node:code_build_lines.data.poIds}} || [];
const orgId = {{node:code_build_lines.data.organizationId}} || '';
const plantId = {{node:code_build_lines.data.plantId}} || '';
const grRemark1 = {{node:code_build_lines.data.grRemark1}} || '';
const grRemark2 = {{node:code_build_lines.data.grRemark2}} || '';
const grRemark3 = {{node:code_build_lines.data.grRemark3}} || '';
const grRemark4 = {{node:code_build_lines.data.grRemark4}} || '';
const grRemark5 = {{node:code_build_lines.data.grRemark5}} || '';
const skipPutaway = {{node:code_build_lines.data.skipPutaway}} || 0;
const gdId = {{workflowparams:gd_id}} || '';
const gdNo = {{workflowparams:gd_no}} || '';

const itemMap = {};
for (const it of itemArr) { if (it && it.id) itemMap[String(it.id)] = it; }
const countryMap = {};
for (const c of countryArr) { if (c && c.id) countryMap[String(c.id)] = c.country_name; }
const stateMap = {};
for (const s of stateArr) { if (s && s.id) stateMap[String(s.id)] = s.state_name; }

const convertAltToBase = (altQty, table, altUOM) => {
  if (!Array.isArray(table) || table.length === 0 || !altUOM) return altQty;
  const c = table.find((x) => x.alt_uom_id === altUOM);
  if (!c || !c.alt_qty) return altQty;
  return Math.round(altQty * c.base_qty * 1000) / 1000;
};

const putawayCategory = (putawaySetup && putawaySetup.category) ? putawaySetup.category : 'In Transit';

// --- GD batch enrichment inputs (GD table passed from GDheadWorkflow; SO + Batch fetched here) ---
const gdTable = {{workflowparams:gd_table}} || [];
const soRows = {{node:search_so.data.data}};
const soArr = Array.isArray(soRows) ? soRows : (soRows ? [soRows] : []);
const batchRows = {{node:search_batch.data.data}};
const batchArr = Array.isArray(batchRows) ? batchRows : (batchRows ? [batchRows] : []);

// SO line id -> source PO line item id (stamped by auto-SO creation)
const soLineToPoLine = {};
for (const so of soArr) {
  if (!so || !Array.isArray(so.table_so)) continue;
  for (const sl of so.table_so) {
    if (sl && sl.id && sl.source_po_line_item_id) soLineToPoLine[String(sl.id)] = String(sl.source_po_line_item_id);
  }
}
// batch id -> { batch_number, manufacturing_date, expired_date }
const batchInfo = {};
for (const b of batchArr) {
  if (b && b.id) batchInfo[String(b.id)] = { batch_number: b.batch_number || '', manufacturing_date: b.manufacturing_date || null, expired_date: b.expired_date || null };
}
// PO line item id -> { order:[batchId...], map:{batchId:qty} } aggregated across GD lines
const poLineBatches = {};
for (const gl of gdTable) {
  if (!gl) continue;
  const poLineId = gl.so_line_item_id ? soLineToPoLine[String(gl.so_line_item_id)] : null;
  if (!poLineId) continue;
  let tqd = [];
  try { tqd = gl.temp_qty_data ? JSON.parse(gl.temp_qty_data) : []; } catch (e) { tqd = []; }
  if (!Array.isArray(tqd)) tqd = [];
  if (!poLineBatches[poLineId]) poLineBatches[poLineId] = { order: [], map: {} };
  const grp = poLineBatches[poLineId];
  for (const t of tqd) {
    if (!t) continue;
    const q = parseFloat(t.gd_quantity) || 0;
    if (q <= 0) continue;
    const bId = t.batch_id ? String(t.batch_id) : 'none';
    if (grp.map[bId] === undefined) { grp.map[bId] = 0; grp.order.push(bId); }
    grp.map[bId] += q;
  }
}
const letterSuffix = (n) => { let s = ''; let x = n; while (x >= 0) { s = String.fromCharCode(65 + (x % 26)) + s; x = Math.floor(x / 26) - 1; } return s; };

const buildRec = (item, itemData, rowQty, batchNo, mfgDate, expDate, splitInfo) => {
  const rec = Object.assign({}, item);
  rec.base_ordered_qty = item.ordered_qty;
  rec.base_ordered_qty_uom = item.ordered_qty_uom || null;
  rec.base_item_uom = item.ordered_qty_uom || null;
  rec.base_received_qty_uom = item.ordered_qty_uom || null;
  rec.inspection_required = (itemData && itemData.receiving_inspection === 1) ? 'Yes' : 'No';
  rec.to_received_qty = 0;
  rec.received_qty = rowQty;
  rec.base_received_qty = parseFloat((Number(rowQty) || 0).toFixed(3));
  rec.storage_location_id = defaultStorageLocation;
  rec.location_id = defaultBinLocation;
  rec.item_batch_no = batchNo;
  rec.manufacturing_date = mfgDate;
  rec.expired_date = expDate;
  rec.inv_category = '';
  rec.item_costing_method = itemData ? (itemData.material_costing_method || null) : null;
  rec.uom_conversion = 0;
  rec.is_split = splitInfo ? 'Yes' : 'No';
  rec.parent_or_child = splitInfo ? 'Split-Parent' : 'Parent';
  rec.parent_index = splitInfo ? splitInfo.parentIndex : 0;
  if (splitInfo) rec.line_index = splitInfo.lineIndex;

  const isAltUOM = (itemData && itemData.table_uom_conversion)
    ? itemData.table_uom_conversion.find((c) => c.alt_uom_id === item.ordered_qty_uom && c.alt_uom_id !== itemData.based_uom)
    : null;
  if (isAltUOM) {
    rec.base_ordered_qty = convertAltToBase(item.ordered_qty, itemData.table_uom_conversion, item.ordered_qty_uom);
    rec.base_ordered_qty_uom = itemData.based_uom;
    rec.base_received_qty_uom = itemData.based_uom;
    rec.base_item_uom = itemData.based_uom;
    rec.base_received_qty = convertAltToBase(Number(rowQty) || 0, itemData.table_uom_conversion, item.ordered_qty_uom);
    rec.uom_conversion = isAltUOM.base_qty;
  }
  if (itemData && itemData.serial_number_management === 1) rec.is_serialized_item = 1;
  if (itemData && itemData.formula && itemData.formula !== '') { rec.has_formula = 1; rec.formula = itemData.formula; }

  let invCat = '';
  if (rec.inspection_required === 'No') {
    if (!putawaySetup || putawaySetup.putaway_required === 0) invCat = 'Unrestricted';
    else if (putawaySetup.putaway_required === 1) invCat = putawayCategory;
  } else {
    invCat = 'Quality Inspection';
  }
  rec.inv_category = invCat;
  // skip_putaway: force straight-to-Unrestricted (overrides Quality Inspection too)
  if (skipPutaway === 1) { rec.inspection_required = 'No'; rec.inv_category = 'Unrestricted'; }
  return rec;
};

const tableGr = [];
for (let li = 0; li < baseLines.length; li++) {
  const item = baseLines[li];
  const itemData = item.item_id ? itemMap[String(item.item_id)] : null;
  const isBatchItem = itemData && itemData.item_batch_management !== 0;
  const isAutoGen = itemData && itemData.batch_number_genaration === 'According To System Settings';
  const defaultBatchNo = itemData
    ? (itemData.item_batch_management === 0 ? '-' : (isAutoGen ? 'Auto-generated batch number' : ''))
    : '-';

  const grp = poLineBatches[item.po_line_item_id];
  const batchIds = (isBatchItem && grp && grp.order.length > 0) ? grp.order : null;

  // No batch breakdown (non-batch item, or unmapped/legacy SO) -> single row, current behavior
  if (!batchIds) {
    const rec = buildRec(item, itemData, item.received_qty, defaultBatchNo, null, null, null);
    if (Number(rec.received_qty) !== 0) tableGr.push(rec);
    continue;
  }

  // Distribute the PO line's received qty across seller batches proportionally
  const R = parseFloat((Number(item.received_qty) || 0).toFixed(3));
  const totalGd = batchIds.reduce((s, b) => s + (grp.map[b] || 0), 0);
  const multi = batchIds.length >= 2;
  let allocated = 0;
  for (let bi = 0; bi < batchIds.length; bi++) {
    const bId = batchIds[bi];
    let rowQty;
    if (bi === batchIds.length - 1) {
      rowQty = parseFloat((R - allocated).toFixed(3));
    } else {
      rowQty = totalGd > 0 ? parseFloat((R * (grp.map[bId] / totalGd)).toFixed(3)) : 0;
      allocated = parseFloat((allocated + rowQty).toFixed(3));
    }
    if (rowQty <= 0) continue;
    const info = (bId !== 'none' && batchInfo[bId]) ? batchInfo[bId] : null;
    let batchNo;
    if (itemData && itemData.item_batch_management === 0) batchNo = '-';
    else if (isAutoGen) batchNo = 'Auto-generated batch number';
    else batchNo = info ? info.batch_number : defaultBatchNo;
    const mfg = info ? info.manufacturing_date : null;
    const exp = info ? info.expired_date : null;
    const splitInfo = multi ? { parentIndex: li, lineIndex: (li + 1) + '-' + letterSuffix(bi) } : null;
    const rec = buildRec(item, itemData, rowQty, batchNo, mfg, exp, splitInfo);
    if (Number(rec.received_qty) !== 0) tableGr.push(rec);
  }
}

let supplierContactPerson = '';
let supplierContactNumber = '';
let supplierEmail = '';
let currencyCode = poCurrency;
const addrFields = {};
if (supplier) {
  if (supplier.contact_list && supplier.contact_list.length) {
    const c0 = supplier.contact_list[0];
    supplierContactPerson = ((c0.person_name || '') + ' ' + (c0.person_last_name || '')).trim();
    supplierContactNumber = c0.phone_number || '';
    supplierEmail = c0.person_email || '';
  }
  if (supplierCurrencyCode) currencyCode = supplierCurrencyCode;
  const addresses = (supplier.address_list || []).filter((a) => a.switch_save_as_default);
  for (const address of addresses) {
    const country = address.address_country_id ? (countryMap[String(address.address_country_id)] || '') : '';
    const state = address.adddress_state ? (stateMap[String(address.adddress_state)] || '') : '';
    const isShipping = address.address_purpose_id === shippingPurposeId;
    const addressType = isShipping ? 'shipping' : 'billing';
    const addressTypeUpperCase = isShipping ? 'Shipping' : 'Billing';
    const lineParts = [address.address_line_1, address.address_line_2, address.address_line_3, address.address_line_4].filter((l) => l);
    const addressLines = lineParts.join((lineParts[lineParts.length - 1] || '').endsWith(',') ? ' ' : ', ');
    const cityParts = [address.address_city, address.address_postal_code, address.adddress_state ? state : '', address.address_country_id ? country : ''].filter((d) => d);
    const cityDetails = cityParts.join((cityParts[cityParts.length - 1] || '').endsWith(',') ? ' ' : ', ');
    const addressAttention = address.address_attention ? '\nAttention: ' + address.address_attention : '';
    const addressPurposeName = '\n' + addressTypeUpperCase + ' Address';
    const personParts = [address.address_name, address.address_phone].filter((p) => p);
    const addressPerson = personParts.length > 0 ? personParts.join(' | ') : '';
    const formattedAddress = [addressPerson, addressPurposeName, addressLines, cityDetails, addressAttention].filter(Boolean).join('\n');
    addrFields[addressType + '_address_line_1'] = address.address_line_1;
    addrFields[addressType + '_address_line_2'] = address.address_line_2;
    addrFields[addressType + '_address_line_3'] = address.address_line_3;
    addrFields[addressType + '_address_line_4'] = address.address_line_4;
    addrFields[addressType + '_address_city'] = address.address_city;
    addrFields[addressType + '_address_state'] = address.adddress_state;
    addrFields[addressType + '_postal_code'] = address.address_postal_code;
    addrFields[addressType + '_address_country'] = address.address_country_id;
    addrFields[addressType + '_address_name'] = address.address_name;
    addrFields[addressType + '_address_phone'] = address.address_phone;
    addrFields[addressType + '_attention'] = address.address_attention;
    addrFields['gr_' + addressType + '_address'] = formattedAddress;
  }
}

const today = new Date().toISOString().split('T')[0];

const grAllData = Object.assign({
  gr_status: 'Draft',
  page_status: 'Add',
  from_convert: 'Yes',
  plant_id: plantId,
  organization_id: orgId,
  purchase_order_number: poNos,
  po_id: poIds,
  gr_no: '',
  gr_no_type: grNoType,
  gr_date: today,
  gr_received_by: 'Internal Trading System',
  supplier_name: supplierId,
  currency_code: currencyCode,
  acc_integration_type: accType,
  supplier_contact_person: supplierContactPerson,
  supplier_contact_number: supplierContactNumber,
  supplier_email: supplierEmail,
  gr_remark1: grRemark1,
  gr_remark2: grRemark2,
  gr_remark3: grRemark3,
  gr_remark4: grRemark4,
  gr_remark5: grRemark5,
  table_gr: tableGr
}, addrFields);

return { grAllData: grAllData, skipPutaway: skipPutaway, lineCount: tableGr.length };

const r = {{node:wf_complete_gr.data}};
const d = (r && r.data && typeof r.data === 'object') ? r.data : r;
let code = '';
let message = '';
let grId = '';
let grNo = '';
if (d) {
  code = (d.code !== undefined && d.code !== null) ? d.code : '';
  message = (d.message !== undefined && d.message !== null) ? d.message : '';
  grId = d.id || '';
  grNo = d.gr_no || '';
}
const grOk = (String(code) === '200') ? 1 : 0;
return { grOk: grOk, grCode: String(code || ''), grMessage: message || '', grId: grId || '', grNo: grNo || '' };
